// // This module adjusts the operating frequency and voltage of a processing unit based on the input load.
// It monitors a 3-bit input signal representing the load (from 0 to 7) and adjusts the output frequency (also 3-bits) and voltage (2-bits) accordingly.
// The frequency and voltage levels should follow these rules:
// - Load 0: Frequency = 111, Voltage = 00
// - Load 1: Frequency = 110, Voltage = 01
// - Load 2: Frequency = 101, Voltage = 01
// - Load 3: Frequency = 100, Voltage = 10
// - Load 4: Frequency = 011, Voltage = 10
// - Load 5: Frequency = 010, Voltage = 11
// - Load 6: Frequency = 001, Voltage = 11
// - Load 7: Frequency = 000, Voltage = 11
module dvfs_controller (
    input wire clk,
    input wire reset,
    input wire [2:0] load,
    output reg [2:0] frequency,
    output reg [1:0] voltage
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            frequency <= 3'b000;
            voltage <= 2'b00;
        end else begin
            case (load)
                3'b000: begin
                    frequency <= 3'b000; 
                    voltage <= 2'b00; 
                end
                3'b001: begin
                    frequency <= 3'b001; 
                    voltage <= 2'b01; 
                end
                3'b010: begin
                    frequency <= 3'b010; 
                    voltage <= 2'b01; 
                end
                3'b011: begin
                    frequency <= 3'b011; 
                    voltage <= 2'b10; 
                end
                3'b100: begin
                    frequency <= 3'b100; 
                    voltage <= 2'b10; 
                end
                3'b101: begin
                    frequency <= 3'b101; 
                    voltage <= 2'b11; 
                end
                3'b110: begin
                    frequency <= 3'b110; 
                    voltage <= 2'b11; 
                end
                3'b111: begin
                    frequency <= 3'b111; 
                    voltage <= 2'b11; 
                end
                default: begin
                    frequency <= 3'b000; 
                    voltage <= 2'b00; 
                end
            endcase
        end
    end
endmodule

